task.example:
```yaml
# Add after "key_message" field in existing template:

# Agenda Structure with Discovery
agenda:
  total_sections: {{agenda_sections.length}}
  sections:
{{for each section in agenda_sections}}
    - id: "{{section.id}}"
      title: "{{section.title}}"
      narrative_role: "{{section.narrative_role}}"
      estimated_slides: {{section.estimated_slides}}
      description: "{{section.description}}"
      discovery:
        key_message: "{{section.discovery.key_message}}"
        key_message_framing: "{{section.discovery.key_message_framing | default: 'direct'}}"
        diagram_requirements: {{section.discovery.diagram_requirements | default: []}}
        visual_metaphor: {{section.discovery.visual_metaphor | default: []}}
        research_findings: {{section.discovery.research_findings | default: []}}
{{end for}}

# Modify slides array to include agenda_section_id:
slides:
{{for each slide in slides}}
  - number: {{slide.number}}
    intent: "{{slide.intent}}"
    template: "{{slide.template}}"
    status: pending
    storyline_role: "{{slide.storyline_role}}"
    agenda_section_id: "{{slide.agenda_section_id}}"
    # ... rest of slide fields
{{end for}}
```
